// The export destination screen. Shown after a format is chosen — lets
// the person pick where the file goes, rather than the app guessing:
//  - "Save As…" uses the browser's real file-save dialog (Chrome/Edge)
//    when available, so the person can navigate to any folder — including
//    a Google Drive or Dropbox folder synced to their device, which is
//    the standard way "saving to Drive" works from a website.
//  - "Download" is the classic one-click download as a fallback.
//  - Drive/Dropbox buttons open those services directly so the file
//    (already downloaded or copied) can be dropped in right away.
//  - Copy-to-clipboard is the last-resort guarantee that always works.
function ExportResultModal({ filename, content, mime, onClose }) {
  const [copied, setCopied] = useState(false);
  const [saveMsg, setSaveMsg] = useState("");
  const canPickLocation = typeof window !== "undefined" && !!window.showSaveFilePicker;

  const saveAs = async () => {
    try {
      const handle = await window.showSaveFilePicker({ suggestedName: filename });
      const writable = await handle.createWritable();
      await writable.write(content);
      await writable.close();
      setSaveMsg("Saved.");
    } catch (e) {
      if (e?.name !== "AbortError") setSaveMsg("Couldn't save that way on this device — try Download instead.");
    }
  };

  return (
    <div style={styles.exportOverlay} onClick={onClose}>
      <div style={styles.exportMenu} onClick={(e) => e.stopPropagation()}>
        <div style={styles.exportMenuTitle}>{filename}</div>
        <textarea readOnly value={content} style={styles.exportResultArea} dir="ltr" />

        {canPickLocation && (
          <button style={styles.exportOption} onClick={saveAs}>
            Save As… (choose a folder on this device)
          </button>
        )}
        <button style={styles.exportOption} onClick={() => downloadFile(filename, content, mime)}>
          Download to this device
        </button>
        <div style={styles.exportDestRow}>
          <button
            style={styles.exportDestBtn}
            onClick={() => window.open("https://drive.google.com/drive/my-drive", "_blank")}
          >
            Open Google Drive
          </button>
          <button
            style={styles.exportDestBtn}
            onClick={() => window.open("https://www.dropbox.com/home", "_blank")}
          >
            Open Dropbox
          </button>
        </div>
        {saveMsg && <div style={styles.exportHint}>{saveMsg}</div>}

        <button
          style={{ ...styles.exportOption, ...styles.navBtnWithIcon, justifyContent: "center" }}
          onClick={async () => {
            const ok = await copyToClipboard(content);
            setCopied(ok);
            setTimeout(() => setCopied(false), 2000);
          }}
        >
          {copied && <Check size={15} />}
          {copied ? "Copied" : "Copy to clipboard"}
        </button>
        <div style={styles.exportHint}>
          Downloaded or copied this file? Open Drive or Dropbox above and drop
          it into the upload area there — that's the same last step any
          app takes to get a file into cloud storage.
        </div>
        <button style={styles.cancelBtn} onClick={onClose}>Close</button>
      </div>
    </div>
  );
}

